import { useMemo, useState } from "react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";
import { formatCurrencyValue, useCurrencyVersion } from "@/lib/currency";

const FAQS = [
  { q: "What is a HELOC?", a: "A HELOC is a home equity line of credit. It lets homeowners borrow against available equity as needed during a draw period." },
  { q: "How does a HELOC draw period work?", a: "During the draw period, you can usually borrow, repay, and borrow again up to your credit limit. Payments are often interest-only during this phase." },
  { q: "How is HELOC interest calculated?", a: "HELOC interest is typically calculated on the outstanding balance, not the full approved credit limit." },
  { q: "What is the difference between a HELOC and a home equity loan?", a: "A HELOC is flexible revolving credit, while a home equity loan gives one lump sum with a fixed repayment schedule." },
  { q: "Can you pay off a HELOC early?", a: "Most HELOCs allow early payoff, but some lenders may charge early closure or annual fees. Check the loan terms." },
];

const money = (v: number, d = 2) => formatCurrencyValue(Number.isFinite(v) ? v : 0, { maximumFractionDigits: d });
const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";

function pmt(principal: number, rate: number, years: number) {
  const r = rate / 100 / 12;
  const n = years * 12;
  if (principal <= 0 || n <= 0) return 0;
  return r === 0 ? principal / n : principal * r / (1 - Math.pow(1 + r, -n));
}

export default function HELOCCalculator() {
  useCurrencyVersion();
  const [homeValue, setHomeValue] = useState(450000);
  const [mortgageBalance, setMortgageBalance] = useState(260000);
  const [creditLimit, setCreditLimit] = useState(80000);
  const [drawYears, setDrawYears] = useState(10);
  const [rate, setRate] = useState(8.5);
  const [monthlyDraw, setMonthlyDraw] = useState(800);
  const [repaymentYears, setRepaymentYears] = useState(15);

  const result = useMemo(() => {
    const maxLimit = Math.max(0, homeValue * 0.85 - mortgageBalance);
    const approvedLimit = Math.min(Math.max(0, creditLimit), maxLimit);
    const drawnBalance = Math.min(approvedLimit, Math.max(0, monthlyDraw) * drawYears * 12);
    const monthlyInterest = drawnBalance * rate / 100 / 12;
    const repaymentPayment = pmt(drawnBalance, rate, repaymentYears);
    const drawInterest = monthlyInterest * drawYears * 12;
    const repaymentInterest = repaymentPayment * repaymentYears * 12 - drawnBalance;
    return { maxLimit, approvedLimit, drawnBalance, monthlyInterest, repaymentPayment, totalInterest: drawInterest + repaymentInterest, totalCost: drawnBalance + drawInterest + repaymentInterest };
  }, [homeValue, mortgageBalance, creditLimit, drawYears, rate, monthlyDraw, repaymentYears]);

  const rows = [
    ["Rate Type", "Usually variable", "Usually fixed", "Choose fixed when you want predictable payments"],
    ["Access", "Borrow as needed", "One lump sum", "Choose HELOC for flexible projects"],
    ["Draw Period", "Commonly 5 to 10 years", "No draw period", "Choose HELOC when costs happen over time"],
    ["Monthly Payment", "Often interest-only first", "Fixed principal and interest", "Choose loan for steady payoff"],
    ["Best For", "Renovations and flexible needs", "One-time large expense", "Match the loan to how you spend"],
  ];

  return (
    <>
      <SEOHead title="Free HELOC Calculator Online - Calculate Home Equity Line of Credit Payments Instantly | CalcHive" description="Free online HELOC calculator. Calculate monthly payments during draw and repayment periods for any home equity line of credit amount and rate instantly. 100% free, no signup required." canonical="/heloc-calculator" keywords="free HELOC calculator, home equity line of credit calculator free, HELOC payment calculator free online, calculate HELOC interest free, HELOC vs home equity loan calculator free" category="Financial Calculators" breadcrumbName="Free HELOC Calculator Online" schemaType="WebApplication" schemaApplicationCategory="CalculatorApplication" faqs={FAQS} />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8"><span className="text-xs font-semibold uppercase tracking-widest text-sky-600 dark:text-sky-400 bg-sky-50 dark:bg-sky-950/50 px-3 py-1 rounded-full mb-4 inline-block">Financial</span><h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free HELOC Calculator Online</h1><p className="text-muted-foreground leading-relaxed">Estimate HELOC draw-period interest, repayment payment, total interest, and total cost.</p></div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8"><div><label className="text-sm font-semibold text-foreground block mb-2">Home value</label><input type="number" value={homeValue} onChange={(e) => setHomeValue(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Mortgage balance</label><input type="number" value={mortgageBalance} onChange={(e) => setMortgageBalance(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">HELOC credit limit</label><input type="number" value={creditLimit} onChange={(e) => setCreditLimit(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Draw period years</label><input type="number" value={drawYears} onChange={(e) => setDrawYears(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Interest rate (%)</label><input type="number" value={rate} onChange={(e) => setRate(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Monthly draw amount</label><input type="number" value={monthlyDraw} onChange={(e) => setMonthlyDraw(Number(e.target.value))} className={inputClass} /></div><div><label className="text-sm font-semibold text-foreground block mb-2">Repayment years</label><input type="number" value={repaymentYears} onChange={(e) => setRepaymentYears(Number(e.target.value))} className={inputClass} /></div></div>
          <div className="bg-gradient-to-br from-sky-500 to-sky-700 rounded-2xl p-6 text-center shadow-lg"><p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Repayment Period Payment</p><p className="text-5xl sm:text-6xl font-black text-white">{money(result.repaymentPayment)}</p></div>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3 mt-4"><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Draw period interest</p><p className="text-lg font-extrabold text-foreground">{money(result.monthlyInterest)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Drawn balance</p><p className="text-lg font-extrabold text-foreground">{money(result.drawnBalance)}</p></div><div className="bg-accent/60 border border-border rounded-xl p-4 text-center"><p className="text-xs text-muted-foreground">Total interest</p><p className="text-lg font-extrabold text-foreground">{money(result.totalInterest)}</p></div></div>
        </section>
        <ShareButton />
        <section className="mb-8 space-y-6"><h2 className="text-2xl font-bold text-foreground">How to Calculate HELOC Payments During Draw and Repayment Periods for Free</h2><p className="text-muted-foreground leading-relaxed">During the draw period, interest is estimated from the outstanding balance. During repayment, the balance is amortized over the repayment term.</p><h2 className="text-2xl font-bold text-foreground">HELOC vs Home Equity Loan - Which Is Better</h2><div className="overflow-x-auto"><table className="w-full text-sm border border-border rounded-xl overflow-hidden"><caption className="caption-top text-left font-bold text-foreground mb-3">HELOC vs Home Equity Loan Comparison - $80,000 Borrowing</caption><thead className="bg-muted/60"><tr>{["Feature", "HELOC", "Home Equity Loan", "When to Choose"].map((h) => <th key={h} className="text-left py-3 px-3 font-semibold text-foreground">{h}</th>)}</tr></thead><tbody className="divide-y divide-border">{rows.map((row) => <tr key={row[0]}><td className="py-2.5 px-3 font-semibold">{row[0]}</td><td className="py-2.5 px-3">{row[1]}</td><td className="py-2.5 px-3">{row[2]}</td><td className="py-2.5 px-3">{row[3]}</td></tr>)}</tbody></table></div><h2 className="text-2xl font-bold text-foreground">Free Home Equity Line of Credit Calculator for Homeowners</h2><p className="text-muted-foreground leading-relaxed">Use this HELOC estimate to compare flexible borrowing against a fixed home equity loan.</p></section>
        <section className="mb-8"><h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3><div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div></section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" /><RelatedTools exclude="/heloc-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


